var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"최종 재배포 버전 조합 완료율...... 99%.","JPN":"最終再配布版の組み合わせ完了率……99％。","ENG":"The completion rate of the final redistributable version... 99%.","TWN":"最終再分發版本融合達成率……99%。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"바보 같군, 유미나.","JPN":"バカだな、ヤナギ・ミナ。","ENG":"How foolish, Yoo Mina.","TWN":"妳這笨蛋，劉米娜。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"넌 이미 날 한 번 살려줬지만 난 여전히 리플레이서에 협력하고 있다.","JPN":"あなたは一度私のことを助けてくれましたが、私は今なおリプレイサーに協力している。","ENG":"You already spared my life before, only to send me back to working with the Replacers.","TWN":"妳已經放過我一次了，但我仍然在和克隆集團合作。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그런데도 날 죽이는 걸 포기하다니 대체 무슨 생각을 하는 거지?","JPN":"それなのに、私を殺すのを断念するなんて、いったい何を考えている？","ENG":"And yet you're choosing not to kill me again? What are you thinking?","TWN":"而妳竟然還是放棄要殺死我，妳究竟在想什麼？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"머릿속이 꽃밭으로 가득 차 있기라도 하나?","JPN":"頭の中、お花畑なのか？","ENG":"You seem more happy-go-lucky than a kid frolicking around the field of flowers.","TWN":"難道妳的腦袋裡開滿了花田嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양과 꽃밭이라니...... 참 안 어울리는 조합이네요. 하하.","JPN":"ミナさんとお花畑か……この上なく不釣り合いですね、ハハ。","ENG":"Mina and flowers? What a weird combination, Hah hah.","TWN":"米娜小姐和花田……這個組合真是一點也不搭呢，哈哈。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는 또 무슨 소릴 하고 있는 거야?! 그럴 리가 없잖아!","JPN":"先輩、真に受けないでよね！？　例えに決まってるでしょ！","ENG":"You're finding that funny, Shiyoon? I'm not happy-go-lucky!","TWN":"前輩又在說什麼？！才不會不搭好嗎！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 비숍, 널 믿고 있을 뿐이야.","JPN":"私はね、ビショップ、あんたを信じてるだけだよ。","ENG":"I believe in you, Bishop, that's all.","TWN":"我只是相信大主教，相信妳而已。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌 나래가 아니지만...... 네 안에 나래의 일부분이라도 남아 있다면 네가 그런 끔찍한 선택을 할 리가 없어.","JPN":"あんたはナルミではないけど……あんたの中にナルミの一部でも残っていたら、\\nあんな残酷な選択をするはずない。","ENG":"You’re not Narae, but if there's the tiniest part of her left within you, you won't make such a terrible decision.","TWN":"雖然妳不是娜拉……但只要妳體內還留有娜拉的一部分，妳一定不會做出那種可怕的選擇。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"바보 같은 소리로군.","JPN":"バカげたことを。","ENG":"How ridiculous.","TWN":"真是蠢話啊。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"비숍을 테라사이드 시스템의 의사조정자로 선택한 건 그녀가 연산기능에 특화된 진화체인 이유만이 아니다.","JPN":"ビショップをテラサイドシステムの意思調整者に決めたのは、\\n彼女が演算能力に長けた進化体だからという理由だけではない。","ENG":"Bishop having been chosen as the Arbiter of System Terraside wasn't just because she was a Replacer with high calculation capabilities.","TWN":"我之所以會選擇主教作為特拉賽德系統的裁決者，不只是因為她是演算功能得到特化的進化體，"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"더욱 중요한 건 그녀의 모체인 신나래가 절대로 우리를 배신하지 않을 존재이기 때문이다.","JPN":"それよりも大事なのは、彼女の母体であるシンジョウ・ナルミが、\\n決して我々を裏切ったりしない存在だからだ。","ENG":"It was rather because her source, Shin Narae, was someone who'd never betray us.","TWN":"更重要的是，她的母體申娜拉是絕對不會背叛我們的存在。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고? 네가 나래에 대해서 뭘 안다고 떠들어?!","JPN":"何だって？　あんたにナルミの何がわかるっていうのよ！？","ENG":"What? What do you know about her?","TWN":"什麼？你又知道娜拉的什麼了？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"적어도 되살아난 후의 그녀에 대해서는 자네보다 잘 안다고 할 수 있지.","JPN":"少なくとも、生き返った後の彼女については、君より詳しいと言えるよ。","ENG":"I know much better than you about what she was like after she came back to life.","TWN":"至少我比妳更瞭解重生之後的她。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그녀와 직접 싸워본 자네라면 알겠지? 그녀가 얼마나 자네와 세상을 증오했는지.","JPN":"彼女と直接対決した君ならわかるだろう？　彼女がどれほど君のことや社会を憎んでいたか。","ENG":"You fought her yourself. You should know how much she hated you, and all the rest of the world.","TWN":"有和她直接戰鬥過的妳一定知道吧？她有多麼憎恨妳和這個世界。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 재생체는 별개의 인격체이지만 어쩔 수 없이 모체의 감정선에 영향을 받을 수밖에 없다.","JPN":"リプレイサー再生体は別の人格だが、必然的に母体の感情に影響される。","ENG":"It's true that a Regenerated Replacer is a separate entity from its source, but it can't be completely free from the residue of emotions inherited from the source.","TWN":"克隆再生體雖然是不同的人格，但卻不得不接受母體情感帶來的影響。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};